import React, { useState, useEffect, useRef } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, ShoppingCart, Store, Radar, BellRing } from 'lucide-react';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

// --- UTILIDAD DE DISTANCIA ---
const calcularDistanciaRadar = (lat1, lon1, lat2, lon2) => {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLon/2) * Math.sin(dLon/2);
  return R * (2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a)));
};

const PanelCliente = () => {
  const [tab, setTab] = useState('tienda'); 
  const [ofertasPorLocal, setOfertasPorLocal] = useState({});
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [verCarrito, setVerCarrito] = useState(false);
  const [miUbicacion, setMiUbicacion] = useState(null);
  
  const [radarActivo, setRadarActivo] = useState(false);
  const [notificaciones, setNotificaciones] = useState([]);
  const [favoritos, setFavoritos] = useState([]); 

  const searchTimer = useRef(null);
  const currentUserId = localStorage.getItem('user-id');

  // --- LÓGICA DE APRENDIZAJE ---
  const registrarInteres = (terminos) => {
    const palabras = Array.isArray(terminos) ? terminos : [terminos];
    setFavoritos(prev => {
      let nuevosFavs = [...prev];
      palabras.forEach(p => {
        const limpia = p.toLowerCase().split(' ')[0].replace(/[^a-z]/g, '');
        if (limpia.length > 2 && !nuevosFavs.includes(limpia)) {
          nuevosFavs.push(limpia);
        }
      });
      const sliceFinal = nuevosFavs.slice(-15);
      localStorage.setItem(`favs-${currentUserId}`, JSON.stringify(sliceFinal));
      return sliceFinal;
    });
  };

  useEffect(() => {
    const handleCompraEvent = (e) => registrarInteres(e.detail);
    window.addEventListener('app:aprenderInteres', handleCompraEvent);
    const guardados = JSON.parse(localStorage.getItem(`favs-${currentUserId}`) || "[]");
    setFavoritos(guardados);
    return () => window.removeEventListener('app:aprenderInteres', handleCompraEvent);
  }, [currentUserId]);

  // --- LÓGICA DE PEDIDOS ---
  const handlePago = (total) => {
    if (cart.length === 0) return;
    const nuevoPedido = {
      id: `PED-${Date.now()}`,
      clienteId: currentUserId,
      total,
      fecha: new Date().toLocaleString(),
      estado: 'proceso',
      items: [...cart]
    };
    const todos = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    localStorage.setItem('historial-pedidos', JSON.stringify([nuevoPedido, ...todos]));
    setPedidos([nuevoPedido, ...pedidos]);
    setCart([]);
    setVerCarrito(false);
    setTab('proceso');
    registrarInteres(cart.map(i => i.producto));
  };

  const finalizarPedido = (id) => {
    const todos = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    const actualizados = todos.map(p => p.id === id ? { ...p, estado: 'completado' } : p);
    localStorage.setItem('historial-pedidos', JSON.stringify(actualizados));
    setPedidos(pedidos.map(p => p.id === id ? { ...p, estado: 'completado' } : p));
  };

  // --- RADAR Y CARGA ---
  useEffect(() => {
    let watchId = null;
    if (radarActivo && navigator.geolocation) {
      watchId = navigator.geolocation.watchPosition((pos) => {
        const { latitude, longitude } = pos.coords;
        setMiUbicacion({ lat: latitude, lng: longitude });
        const encontradas = [];
        Object.values(ofertasPorLocal).forEach(grupo => {
          grupo.ofertas.forEach(o => {
            const coincide = favoritos.some(fav => o.producto.toLowerCase().includes(fav));
            if (coincide) {
              const d = calcularDistanciaRadar(latitude, longitude, grupo.info.lat, grupo.info.lng);
              if (d <= 0.6) encontradas.push({ ...o, dist: d.toFixed(2), localNombre: grupo.info.nombre });
            }
          });
        });
        setNotificaciones(encontradas);
      }, null, { enableHighAccuracy: true });
    }
    return () => { if (watchId) navigator.geolocation.clearWatch(watchId); };
  }, [radarActivo, ofertasPorLocal, favoritos]);

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    const agrupado = {};
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      if (ofs.length > 0) agrupado[l.nombre] = { info: l, ofertas: ofs };
    });
    setOfertasPorLocal(agrupado);
    const todos = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    setPedidos(todos.filter(p => p.clienteId === currentUserId));
  }, [currentUserId]);

  const handleBusqueda = (val) => {
    setBusqueda(val);
    if (searchTimer.current) clearTimeout(searchTimer.current);
    searchTimer.current = setTimeout(() => registrarInteres(val), 1500);
  };

  return (
    <div style={layout}>
      <aside style={sidebar}>
        <div style={logoEspacio}>
          <h2 style={{color: '#e67e22', margin: 0}}>OfertasAPP</h2>
          <small style={{color: '#a0aec0'}}>Hola, {localStorage.getItem('user-name')}</small>
        </div>
        <nav style={navItems}>
          <button onClick={() => {setTab('tienda'); setVerCarrito(false)}} style={tab === 'tienda' && !verCarrito ? btnActive : btn}><ShoppingBag size={20}/> Tienda</button>
          <button onClick={() => {setVerCarrito(true); setTab('tienda')}} style={verCarrito ? btnActive : btn}><ShoppingCart size={20}/> Carrito ({cart.length})</button>
          <button onClick={() => {setTab('proceso'); setVerCarrito(false)}} style={tab === 'proceso' ? btnActive : btn}><Clock size={20}/> En Proceso</button>
          <button onClick={() => {setTab('historial'); setVerCarrito(false)}} style={tab === 'historial' ? btnActive : btn}><CheckCircle size={20}/> Historial</button>
        </nav>
      </aside>

      <main style={main}>
        {tab === 'tienda' && !verCarrito && (
          <>
            <div style={radarCard(radarActivo)}>
              <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
                <div style={radarCircle(radarActivo)}><Radar size={24} color={radarActivo ? "#fff" : "#e67e22"} /></div>
                <div style={{flex: 1}}>
                  <h3 style={{margin: 0, fontSize: '1rem'}}>Radar de Ahorro Inteligente</h3>
                  <p style={{margin: 0, fontSize: '0.8rem', opacity: 0.8}}>
                    {radarActivo ? `Vigilando: ${favoritos.join(', ')}` : 'La app aprende tus gustos al buscar o comprar.'}
                  </p>
                </div>
                <button onClick={() => setRadarActivo(!radarActivo)} style={btnRadar(radarActivo)}>
                  {radarActivo ? 'APAGAR' : 'ENCENDER'}
                </button>
              </div>
              {radarActivo && notificaciones.length > 0 && (
                <div style={notifBox}>
                  {notificaciones.map(n => (
                    <div key={n.id} style={notifItem}>
                      <BellRing size={18} color="#e67e22" />
                      <div style={{flex: 1}}>
                        <div style={{fontSize: '0.85rem', fontWeight: 'bold'}}>¡{n.producto} detectado!</div>
                        <div style={{fontSize: '0.75rem'}}>A {n.dist} km en {n.localNombre}</div>
                      </div>
                      <button style={btnIr} onClick={() => setCart([...cart, n])}>+$ {n.precioNuevo}</button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div style={searchBox}>
              <MapPin size={20} color="#e67e22" />
              <input style={input} placeholder="Buscar productos..." value={busqueda} onChange={(e) => handleBusqueda(e.target.value)} />
            </div>

            {Object.keys(ofertasPorLocal).map(nombreLocal => {
              const local = ofertasPorLocal[nombreLocal].info;
              const dist = miUbicacion ? calcularDistanciaRadar(miUbicacion.lat, miUbicacion.lng, local.lat, local.lng).toFixed(1) : "---";
              return (
                <div key={nombreLocal} style={tiendaSeccion}>
                  <div style={headerTienda}>
                    <div style={avatarTienda}><Store size={24} color="#e67e22" /></div>
                    <div>
                      <h3 style={{margin: 0}}>{nombreLocal}</h3>
                      <div style={metaTienda}><span>📍 {local.direccion}</span><span style={{color: '#27ae60', fontWeight: 'bold'}}> • {dist} km</span></div>
                    </div>
                  </div>
                  <div style={scrollRow}>
                    {ofertasPorLocal[nombreLocal].ofertas
                      .filter(o => o.producto.toLowerCase().includes(busqueda.toLowerCase()))
                      .map(o => (
                        <div key={o.id} style={cardShop}>
                          <div style={tagDescuento}>-{Math.round((1 - o.precioNuevo/o.precioViejo)*100)}%</div>
                          <img src={o.imagen} style={imgShop} alt="" />
                          <div style={{padding: '12px'}}>
                            <h4 style={{margin: '0', fontSize: '0.9rem'}}>{o.producto}</h4>
                            <div style={{display: 'flex', gap: '5px'}}><span style={pNuevo}>${o.precioNuevo}</span><span style={pViejo}>${o.precioViejo}</span></div>
                            <button style={btnAdd} onClick={() => setCart([...cart, o])}><ShoppingCart size={14} /> Agregar</button>
                          </div>
                        </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </>
        )}

        {verCarrito && (
          <div style={cartContainerStyle}>
            <Carrito cart={cart} setCart={setCart} onCheckout={handlePago} distanciaReal={miUbicacion ? calcularDistanciaRadar(miUbicacion.lat, miUbicacion.lng, -26.81, -65.21) : 0} />
          </div>
        )}

        {tab === 'proceso' && (
          <div style={centerCont}>
            <h2>Estado de tu envío</h2>
            {pedidos.filter(p => p.estado === 'proceso').map(p => (
              <SeguimientoPedido key={p.id} pedido={p} onFinalizar={finalizarPedido} />
            ))}
          </div>
        )}

        {tab === 'historial' && (
          <div style={centerCont}>
             <h2>Pedidos Finalizados</h2>
             {pedidos.filter(p => p.estado === 'completado').map(p => (
               <div key={p.id} style={historialCard}>
                 <div><div style={{fontWeight: 'bold'}}>Orden #{p.id.slice(-6)}</div><small>{p.fecha}</small></div>
                 <div style={{textAlign: 'right'}}><div style={{color: '#e67e22'}}>${p.total}</div></div>
               </div>
             ))}
          </div>
        )}
      </main>
    </div>
  );
};

// --- ESTILOS ---
const layout = { display: 'flex', height: '100vh', background: '#f8fafc', overflow: 'hidden' };
const sidebar = { width: '260px', background: '#1a202c', color: 'white', display: 'flex', flexDirection: 'column', padding: '20px' };
const logoEspacio = { padding: '20px 0 40px 10px' };
const navItems = { display: 'flex', flexDirection: 'column', gap: '8px' };
const btn = { display: 'flex', alignItems: 'center', gap: '12px', padding: '14px', background: 'none', border: 'none', color: '#a0aec0', cursor: 'pointer', borderRadius: '12px', textAlign: 'left' };
const btnActive = { ...btn, background: '#e67e22', color: 'white' };
const main = { flex: 1, padding: '40px', overflowY: 'auto' };
const searchBox = { display: 'flex', alignItems: 'center', background: 'white', padding: '15px 25px', borderRadius: '15px', marginBottom: '30px' };
const input = { flex: 1, border: 'none', outline: 'none', marginLeft: '10px' };
const tiendaSeccion = { marginBottom: '40px', background: 'white', padding: '20px', borderRadius: '20px' };
const headerTienda = { display: 'flex', alignItems: 'center', gap: '15px', marginBottom: '20px' };
const avatarTienda = { width: '48px', height: '48px', background: '#fff3e0', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const metaTienda = { display: 'flex', gap: '10px', fontSize: '0.85rem', color: '#64748b' };
const scrollRow = { display: 'flex', gap: '20px', overflowX: 'auto', paddingBottom: '10px' };
const cardShop = { minWidth: '200px', background: 'white', borderRadius: '15px', border: '1px solid #e2e8f0', position: 'relative', overflow: 'hidden' };
const imgShop = { width: '100%', height: '120px', objectFit: 'cover' };
const btnAdd = { width: '100%', padding: '10px', background: '#1a202c', color: 'white', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' };
const cartContainerStyle = { maxWidth: '500px', margin: '0 auto' };
const centerCont = { maxWidth: '700px', margin: '0 auto' };
const historialCard = { display: 'flex', justifyContent: 'space-between', padding: '15px', background: 'white', borderRadius: '15px', marginBottom: '10px', border: '1px solid #e2e8f0' };
const pNuevo = { fontWeight: 'bold' };
const pViejo = { textDecoration: 'line-through', color: '#94a3b8', fontSize: '0.8rem' };
const tagDescuento = { position: 'absolute', top: '10px', left: '10px', background: '#e67e22', color: 'white', padding: '4px 8px', borderRadius: '8px', fontSize: '0.7rem', fontWeight: 'bold' };
const radarCard = (activo) => ({ background: activo ? '#1a202c' : '#fff', color: activo ? '#fff' : '#1a202c', padding: '20px', borderRadius: '24px', marginBottom: '25px', border: '1px solid #e2e8f0' });
const radarCircle = (activo) => ({ width: '50px', height: '50px', background: activo ? '#e67e22' : '#fff3e0', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' });
const btnRadar = (activo) => ({ padding: '10px 20px', borderRadius: '12px', border: 'none', background: activo ? '#fff' : '#e67e22', color: activo ? '#e67e22' : '#fff', cursor: 'pointer', fontWeight: 'bold' });
const notifBox = { marginTop: '20px', display: 'flex', flexDirection: 'column', gap: '10px' };
const notifItem = { background: '#f8fafc', padding: '12px', borderRadius: '15px', display: 'flex', alignItems: 'center', gap: '12px', color: '#1a202c' };
const btnIr = { background: '#1a202c', color: 'white', border: 'none', padding: '6px 12px', borderRadius: '8px', cursor: 'pointer' };

export default PanelCliente;
